    input.classList.remove('is-valid');
    if (!input.classList.contains('is-invalid')) input.classList.add('is-invalid');

    if (!group) return;
    let fb = group.querySelector('.invalid-feedback[data-source="va-range-2"]'); // <-- propio de opción 2
    if (!fb) {
      fb = document.createElement('div');
      fb.className = 'invalid-feedback';
      fb.dataset.source = 'va-range-2';
      const help = group.querySelector('small.form-text');
      if (help) group.insertBefore(fb, help); else group.appendChild(fb);
    }
    fb.innerHTML = `<div>${message}</div>`;
  }

  function setValid() {
    input.classList.remove('is-invalid');
    //input.classList.add('is-valid');
    if (!group) return;
    const fb = group.querySelector('.invalid-feedback[data-source="va-range-2"]');
    if (fb) fb.remove();
  }

  function clearFeedback() {
    input.classList.remove('is-invalid', 'is-valid');
    if (!group) return;
    const fb = group.querySelector('.invalid-feedback[data-source="va-range-2"]');
    if (fb) fb.remove();
    if (group.dataset) delete group.dataset.vaModalOpened;
  }

  function abrirModal(id) {
    // 1) Si tienes un botón ancla con acceso a $root
    const btn = document.querySelector('[custom-css-selector="btn_preventivo_valorAsegurado"]');
    if (btn?.__vue__?.$root?.$bvModal) {
      btn.__vue__.$root.$bvModal.show(id);
      return;
    }
    // 2) Fallback: usa el propio input para subir al $root
    if (input?.__vue__?.$root?.$bvModal) {
      input.__vue__.$root.$bvModal.show(id);
    }
  }

  function fmt(n) {
    if (typeof n === 'number' && isFinite(n)) {
      try { return n.toLocaleString('es-EC'); } catch { return String(n); }
    }
    return String(n);
  }
}, 180);

